mapper.select:
SELECT COUNT(*)                       AS total,
       COALESCE(SUM(faq_referenced),0) AS answered,
       COALESCE(SUM(handoff),0)        AS handoffs
  FROM chatbot_response_log
 WHERE created_at >= #{from}
   AND created_at < #{toExclusive}

SELECT COUNT(*)
  FROM chatbot_response_log
 WHERE faq_referenced = 1
   AND created_at >= #{from}
   AND created_at < #{toExclusive}
